/* SmartTR Address admin — tab nav + AJAX + Bootstrap Modal/Toast */
(function(){"use strict";var sidebar=document.getElementById("sidebarTabs"),wpcontent=document.getElementById("wpcontent");if(!sidebar||!wpcontent)return;sidebar.addEventListener("show.bs.offcanvas",function(){requestAnimationFrame(function(){var b=document.querySelector("body > .offcanvas-backdrop");if(b)wpcontent.appendChild(b)})})})();
(function(){"use strict";var tabs=document.querySelectorAll(".admin-tab[role='tab']");var panels=document.querySelectorAll(".tab-panel");tabs.forEach(function(tab){tab.addEventListener("click",function(){if(tab.classList.contains("disabled"))return;tabs.forEach(function(t){t.classList.remove("active");t.setAttribute("aria-selected","false")});panels.forEach(function(p){p.classList.add("d-none")});tab.classList.add("active");tab.setAttribute("aria-selected","true");var target=document.getElementById(tab.dataset.panel);if(target){target.classList.remove("d-none");target.style.animation="none";void target.offsetHeight;target.style.animation=""}var oc=document.getElementById("sidebarTabs");if(oc){var offcanvas=bootstrap.Offcanvas.getInstance(oc);if(offcanvas)offcanvas.hide()}})})})();
(function($){"use strict";if(typeof cecomsmaradAdmin==="undefined")return;var cfg=cecomsmaradAdmin,formDirty=false,ICONS={success:"bi-check-circle-fill text-success",danger:"bi-x-circle-fill text-danger",info:"bi-info-circle-fill text-info"};function showToast(type,msg){var el=document.getElementById("cecomsmaradToast"),ic=document.getElementById("cecomsmaradToastIcon"),bd=document.getElementById("cecomsmaradToastBody");if(!el||!ic||!bd)return;ic.className="bi me-2 "+(ICONS[type]||ICONS.info);bd.textContent=msg;new bootstrap.Toast(el,{delay:4000}).show()}function showModal(title,msg){return new Promise(function(resolve){var mEl=document.getElementById("cecomsmaradModal"),tEl=document.getElementById("cecomsmaradModalTitle"),msgEl=document.getElementById("cecomsmaradModalMessage"),btn=document.getElementById("cecomsmaradModalConfirm");if(!mEl||!btn){resolve(false);return}tEl.textContent=title;msgEl.textContent=msg;var modal=new bootstrap.Modal(mEl);modal.show();function ok(){cleanup();modal.hide();resolve(true)}function dismiss(){cleanup();resolve(false)}function cleanup(){btn.removeEventListener("click",ok);mEl.removeEventListener("hidden.bs.modal",dismiss)}btn.addEventListener("click",ok);mEl.addEventListener("hidden.bs.modal",dismiss,{once:true})})}$(document).on("submit",".cecomsmarad-ajax-form",function(e){e.preventDefault();var $form=$(this),action=$form.data("ajax-action"),$btn=$form.find("[type='submit']");if(action==="cecomsmarad_reimport_data"){showModal(cfg.i18n.reimportTitle,cfg.i18n.confirmReimport).then(function(ok){if(ok)doAjax($form,action,$btn)});return}doAjax($form,action,$btn)});function doAjax($form,action,$btn){var orig=$btn.html();$btn.prop("disabled",true).html('<span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>'+$("<span/>").text(cfg.i18n.saving).html());var data=$form.serialize();data+="&action="+encodeURIComponent(action)+"&_ajax_nonce="+encodeURIComponent(cfg.nonce);$.post(cfg.ajaxUrl,data).done(function(r){if(r.success){formDirty=false;showToast("success",(r.data&&r.data.message)||cfg.i18n.saved);if(r.data&&r.data.reload)setTimeout(function(){window.location.reload()},800)}else{showToast("danger",(r.data&&r.data.message)||cfg.i18n.error)}}).fail(function(){showToast("danger",cfg.i18n.error)}).always(function(){$btn.prop("disabled",false).html(orig)})}$(document).on("change","input, select, textarea",function(){formDirty=true});$(window).on("beforeunload",function(){if(formDirty)return cfg.i18n.unsavedChanges});$(document).on("click",".shortcode-copy-btn",function(){var code=$(this).data("shortcode");if(navigator.clipboard&&code)navigator.clipboard.writeText(code).then(function(){showToast("success",cfg.i18n.shortcodeCopied)})})}(jQuery));
